from typing import List

def assert_equals(expected: any, actual: any) -> None:
    if expected != actual:
        raise AssertionError(f"Expected {expected}, but got {actual}")

def assert_false(condition: bool) -> None:
    if condition:
        raise AssertionError("Condition is True, expected False")

def assert_true(condition: bool) -> None:
    if not condition:
        raise AssertionError("Condition is False, expected True")
